using UnifiedToolkit.Conversion.FirstEdition;using UnifiedToolkit.Conversion.FirstEdition.Upgrades;using UnifiedToolkit.Conversion.Issues;using UnifiedToolkit.Conversion.Mapping;using UnifiedToolkit.XWing;
namespace UnifiedToolkit.Conversion.Converters;
public static class UpgradeConverter { public static (IReadOnlyList<FirstEditionUpgrade> Upgrades,IReadOnlyList<ConversionIssue> Issues) Convert(IEnumerable<UpgradeDefinition> source,ConversionMappingSet mappings){var byId=source.ToDictionary(x=>x.Id,StringComparer.OrdinalIgnoreCase);var result=new List<FirstEditionUpgrade>();var issues=new List<ConversionIssue>();foreach(var map in mappings.Upgrades){if(!byId.TryGetValue(map.SourceId,out var s)){issues.Add(new ConversionIssue{Severity="Error",Category="Upgrade",Code="UnknownUpgradeSource",SourceType="Upgrade",SourceId=map.SourceId,TargetId=map.TargetId,Message="Upgrade mapping references a missing source upgrade."});continue;}result.Add(new FirstEditionUpgrade{Id=map.TargetId,Name=map.Name,Slot=map.Slot,SquadPointCost=map.SquadPointCost,Unique=map.Unique,Factions=map.Factions.ToArray(),ShipRestrictions=map.ShipRestrictions.ToArray(),SizeRestrictions=map.SizeRestrictions.ToArray(),Text=map.Text,Provenance=new ConversionProvenance{SourceId=s.Id,MappingId=map.MappingId,Kind=ConversionKind.Direct,MappingVersion=mappings.Version}});}return(result,issues);}}
